30: // SvcUpdate is a callback from service discovery when service info changes.
31: func (s *DiscoveryServer) SvcUpdate(shard model.ShardKey, hostname string, namespace string, event model.Event) {
32: 	// When a service deleted, we should cleanup the endpoint shards and also remove keys from EndpointIndex to
33: 	// prevent memory leaks.
34: 	if event == model.EventDelete {
35: 		inboundServiceDeletes.Increment()
36: 		s.Env.EndpointIndex.DeleteServiceShard(shard, hostname, namespace, false)
37: 	} else {
38: 		inboundServiceUpdates.Increment()
39: 	}
40: }
41: 
42: // EDSUpdate computes destination address membership across all clusters and networks.
43: // This is the main method implementing EDS.
44: // It replaces InstancesByPort in model - instead of iterating over all endpoints it uses
45: // the hostname-keyed map. And it avoids the conversion from Endpoint to ServiceEntry to envoy
46: // on each step: instead the conversion happens once, when an endpoint is first discovered.
47: func (s *DiscoveryServer) EDSUpdate(shard model.ShardKey, serviceName string, namespace string,
48: 	istioEndpoints []*model.IstioEndpoint,
49: ) {
50: 	inboundEDSUpdates.Increment()
51: 	// Update the endpoint shards
52: 	pushType := s.Env.EndpointIndex.UpdateServiceEndpoints(shard, serviceName, namespace, istioEndpoints, true)
53: 	if pushType == model.IncrementalPush || pushType == model.FullPush {
54: 		// Trigger a push
55: 		s.ConfigUpdate(&model.PushRequest{
56: 			Full:           pushType == model.FullPush,
57: 			ConfigsUpdated: sets.New(model.ConfigKey{Kind: kind.ServiceEntry, Name: serviceName, Namespace: namespace}),
58: 			Reason:         model.NewReasonStats(model.EndpointUpdate),
59: 		})
60: 	}
61: }
62: 
63: // EDSCacheUpdate computes destination address membership across all clusters and networks.
64: // This is the main method implementing EDS.
65: // It replaces InstancesByPort in model - instead of iterating over all endpoints it uses
66: // the hostname-keyed map. And it avoids the conversion from Endpoint to ServiceEntry to envoy
67: // on each step: instead the conversion happens once, when an endpoint is first discovered.
68: //
69: // Note: the difference with `EDSUpdate` is that it only update the cache rather than requesting a push
70: func (s *DiscoveryServer) EDSCacheUpdate(shard model.ShardKey, serviceName string, namespace string,
71: 	istioEndpoints []*model.IstioEndpoint,
72: ) {
73: 	inboundEDSUpdates.Increment()
74: 	// Update the endpoint shards
75: 	s.Env.EndpointIndex.UpdateServiceEndpoints(shard, serviceName, namespace, istioEndpoints, false)
76: }
77: 
78: func (s *DiscoveryServer) RemoveShard(shardKey model.ShardKey) {
79: 	s.Env.EndpointIndex.DeleteShard(shardKey)
80: }
81: 
82: // EdsGenerator implements the new Generate method for EDS, using the in-memory, optimized endpoint
83: // storage in DiscoveryServer.
84: type EdsGenerator struct {
85: 	Cache         model.XdsCache
86: 	EndpointIndex *model.EndpointIndex
87: }
88: 
89: var _ model.XdsDeltaResourceGenerator = &EdsGenerator{}
90: 
91: // Map of all configs that do not impact EDS
92: var skippedEdsConfigs = sets.New(
93: 	kind.Gateway,
94: 	kind.VirtualService,
95: 	kind.WorkloadGroup,
96: 	kind.AuthorizationPolicy,
97: 	kind.RequestAuthentication,
98: 	kind.Secret,
99: 	kind.Telemetry,
100: 	kind.WasmPlugin,
101: 	kind.ProxyConfig,
102: 	kind.DNSName,
103: )
104: 
105: func edsNeedsPush(req *model.PushRequest, proxy *model.Proxy) bool {
106: 	if res, ok := xdsNeedsPush(req, proxy); ok {
107: 		return res
108: 	}
109: 	for config := range req.ConfigsUpdated {
110: 		if !skippedEdsConfigs.Contains(config.Kind) {
111: 			return true
112: 		}
113: 	}
114: 	return false
115: }
116: 
117: func (eds *EdsGenerator) Generate(proxy *model.Proxy, w *model.WatchedResource, req *model.PushRequest) (model.Resources, model.XdsLogDetails, error) {
118: 	if !edsNeedsPush(req, proxy) {
119: 		return nil, model.DefaultXdsLogDetails, nil
120: 	}
121: 	resources, logDetails := eds.buildEndpoints(proxy, req, w)
122: 	return resources, logDetails, nil
123: }
124: 
125: func (eds *EdsGenerator) GenerateDeltas(proxy *model.Proxy, req *model.PushRequest,
126: 	w *model.WatchedResource,
127: ) (model.Resources, model.DeletedResources, model.XdsLogDetails, bool, error) {
128: 	if !edsNeedsPush(req, proxy) {
129: 		return nil, nil, model.DefaultXdsLogDetails, false, nil
130: 	}
131: 	if !shouldUseDeltaEds(req) {
132: 		resources, logDetails := eds.buildEndpoints(proxy, req, w)
133: 		return resources, nil, logDetails, false, nil
134: 	}
135: 
136: 	resources, removed, logs := eds.buildDeltaEndpoints(proxy, req, w)
137: 	return resources, removed, logs, true, nil
138: }
139: 
140: func shouldUseDeltaEds(req *model.PushRequest) bool {
141: 	if !req.Full {
142: 		return false
143: 	}
144: 	return canSendPartialFullPushes(req)
145: }
146: 
147: // canSendPartialFullPushes checks if a request contains *only* endpoints updates except `skippedEdsConfigs`.
148: // This allows us to perform more efficient pushes where we only update the endpoints that did change.
149: func canSendPartialFullPushes(req *model.PushRequest) bool {
150: 	// If we don't know what configs are updated, just send a full push
151: 	if req.Forced {
152: 		return false
153: 	}
154: 	for cfg := range req.ConfigsUpdated {
155: 		if skippedEdsConfigs.Contains(cfg.Kind) {
156: 			// the updated config does not impact EDS, skip it
157: 			// this happens when push requests are merged due to debounce
158: 			continue
159: 		}
160: 		if cfg.Kind != kind.ServiceEntry {
161: 			return false
162: 		}
163: 	}
164: 	return true
165: }
166: 
167: func (eds *EdsGenerator) buildEndpoints(proxy *model.Proxy,
168: 	req *model.PushRequest,
169: 	w *model.WatchedResource,
170: ) (model.Resources, model.XdsLogDetails) {
171: 	var edsUpdatedServices map[string]struct{}
172: 	// canSendPartialFullPushes determines if we can send a partial push (ie a subset of known CLAs).
173: 	// This is safe when only Services has changed, as this implies that only the CLAs for the
174: 	// associated Service changed. Note when a multi-network Service changes it triggers a push with
175: 	// ConfigsUpdated=ALL, so in this case we would not enable a partial push.
176: 	// Despite this code existing on the SotW code path, sending these partial pushes is still allowed;
177: 	// see https://www.envoyproxy.io/docs/envoy/latest/api-docs/xds_protocol#grouping-resources-into-responses
178: 	if !req.Full || canSendPartialFullPushes(req) {
179: 		edsUpdatedServices = model.ConfigNamesOfKind(req.ConfigsUpdated, kind.ServiceEntry)
180: 	}
181: 	var resources model.Resources
182: 	empty := 0
183: 	cached := 0
184: 	regenerated := 0
185: 	for clusterName := range w.ResourceNames {
186: 		if edsUpdatedServices != nil {
187: 			if _, ok := edsUpdatedServices[model.ParseSubsetKeyHostname(clusterName)]; !ok {
188: 				// Cluster was not updated, skip recomputing. This happens when we get an incremental update for a
189: 				// specific Hostname. On connect or for full push edsUpdatedServices will be empty.
190: 				continue
191: 			}
192: 		}
193: 		builder := endpoints.NewEndpointBuilder(clusterName, proxy, req.Push)
194: 
195: 		// We skip cache if assertions are enabled, so that the cache will assert our eviction logic is correct
196: 		if !features.EnableUnsafeAssertions {
197: 			cachedEndpoint := eds.Cache.Get(&builder)
198: 			if cachedEndpoint != nil {
199: 				resources = append(resources, cachedEndpoint)
200: 				cached++
201: 				continue
202: 			}
203: 		}
204: 
205: 		// generate eds from beginning
206: 		{
207: 			l := builder.BuildClusterLoadAssignment(eds.EndpointIndex)
208: 			if l == nil {
209: 				continue
210: 			}
211: 			regenerated++
212: 
213: 			if len(l.Endpoints) == 0 {
214: 				empty++
215: 			}
216: 			resource := &discovery.Resource{
217: 				Name:     l.ClusterName,
218: 				Resource: protoconv.MessageToAny(l),
219: 			}
220: 			resources = append(resources, resource)
221: 			eds.Cache.Add(&builder, req, resource)
222: 		}
223: 	}
224: 	return resources, model.XdsLogDetails{
225: 		Incremental:    len(edsUpdatedServices) != 0,
226: 		AdditionalInfo: fmt.Sprintf("empty:%v cached:%v/%v", empty, cached, cached+regenerated),
227: 	}
228: }
229: 
230: // TODO(@hzxuzhonghu): merge with buildEndpoints
231: func (eds *EdsGenerator) buildDeltaEndpoints(proxy *model.Proxy,
232: 	req *model.PushRequest,
233: 	w *model.WatchedResource,
234: ) (model.Resources, []string, model.XdsLogDetails) {
235: 	edsUpdatedServices := model.ConfigNamesOfKind(req.ConfigsUpdated, kind.ServiceEntry)
236: 	var resources model.Resources
237: 	var removed []string
238: 	empty := 0
239: 	cached := 0
240: 	regenerated := 0
241: 
242: 	for clusterName := range w.ResourceNames {
243: 		// filter out eds that are not updated for clusters
244: 		if _, ok := edsUpdatedServices[model.ParseSubsetKeyHostname(clusterName)]; !ok {
245: 			continue
246: 		}
247: 
248: 		builder := endpoints.NewEndpointBuilder(clusterName, proxy, req.Push)
249: 		// if a service is not found, it means the cluster is removed
250: 		if !builder.ServiceFound() {
251: 			removed = append(removed, clusterName)
252: 			continue
253: 		}
254: 
255: 		// We skip cache if assertions are enabled, so that the cache will assert our eviction logic is correct
256: 		if !features.EnableUnsafeAssertions {
257: 			cachedEndpoint := eds.Cache.Get(&builder)
258: 			if cachedEndpoint != nil {
259: 				resources = append(resources, cachedEndpoint)
260: 				cached++
261: 				continue
262: 			}
263: 		}
264: 		// generate new eds cache
265: 		{
266: 			l := builder.BuildClusterLoadAssignment(eds.EndpointIndex)
267: 			if l == nil {
268: 				removed = append(removed, clusterName)
269: 				continue
270: 			}
271: 			regenerated++
272: 			if len(l.Endpoints) == 0 {
273: 				empty++
274: 			}
275: 			resource := &discovery.Resource{
276: 				Name:     l.ClusterName,
277: 				Resource: protoconv.MessageToAny(l),
278: 			}
279: 			resources = append(resources, resource)
280: 			eds.Cache.Add(&builder, req, resource)
281: 		}
282: 	}
283: 	return resources, removed, model.XdsLogDetails{
284: 		Incremental:    len(edsUpdatedServices) != 0,
285: 		AdditionalInfo: fmt.Sprintf("empty:%v cached:%v/%v", empty, cached, cached+regenerated),
286: 	}
287: }
