36: // IstioControlPlaneInstance defines the format Istio uses for when creating Envoy config.core.v3.ControlPlane.identifier
37: type IstioControlPlaneInstance struct {
38: 	// The Istio component type (e.g. "istiod")
39: 	Component string
40: 	// The ID of the component instance
41: 	ID string
42: 	// The Istio version
43: 	Info istioversion.BuildInfo
44: }
45: 
46: // Evaluate the controlPlane lazily in order to allow "POD_NAME" env var setting after running the process.
47: var controlPlane = lazy.New(func() (*core.ControlPlane, error) {
48: 	// The Pod Name (instance identity) is in PilotArgs, but not reachable globally nor from DiscoveryServer
49: 	podName := env.Register("POD_NAME", "", "").Get()
50: 	byVersion, err := json.Marshal(IstioControlPlaneInstance{
51: 		Component: "istiod",
52: 		ID:        podName,
53: 		Info:      istioversion.Info,
54: 	})
55: 	if err != nil {
56: 		log.Warnf("XDS: Could not serialize control plane id: %v", err)
57: 	}
58: 	return &core.ControlPlane{Identifier: string(byVersion)}, nil
59: })
