102: // isSidecar ad-hoc method to see if connection represents a sidecar
103: func isProxy(con *Connection) bool {
104: 	return con != nil &&
105: 		con.proxy != nil &&
106: 		con.proxy.Metadata != nil &&
107: 		con.proxy.Metadata.ProxyConfig != nil
108: }
