165: func debugSyncStatus(wr model.WatchedResource) status.ConfigStatus {
166: 	if wr.LastError != "" {
167: 		return status.ConfigStatus_ERROR
168: 	}
169: 	if wr.NonceSent == "" {
170: 		return status.ConfigStatus_NOT_SENT
171: 	}
172: 	if wr.NonceAcked == wr.NonceSent {
173: 		return status.ConfigStatus_SYNCED
174: 	}
175: 	return status.ConfigStatus_STALE
176: }
