178: func (sg *StatusGen) debugConfigDump(proxyID string) (model.Resources, error) {
179: 	conn := sg.Server.getProxyConnection(proxyID)
180: 	if conn == nil {
181: 		// This is "like" a 404.  The error is the client's.  However, this endpoint
182: 		// only tracks a single "shard" of connections.  The client may try another instance.
183: 		return nil, fmt.Errorf("config dump could not find connection for proxyID %q", proxyID)
184: 	}
185: 
186: 	dump, err := sg.Server.connectionConfigDump(conn, false)
187: 	if err != nil {
188: 		return nil, err
189: 	}
190: 
191: 	return model.AnyToUnnamedResources(dump.Configs), nil
